import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第十九章 看剑，不看根","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第十九章-看剑，不看根.md","filePath":"永恒道途/正文/第一卷-山门有路/第十九章-看剑，不看根.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第十九章-看剑，不看根.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第十九章-看剑-不看根" tabindex="-1">第十九章 看剑，不看根 <a class="header-anchor" href="#第十九章-看剑-不看根" aria-label="Permalink to &quot;第十九章 看剑，不看根&quot;">​</a></h1><p>青云宗主殿前有九十九级白石阶。</p><p>陈玄走到第二十七级时，右肋开始发紧。昨日赵无锋第一枪擦过左肩，伤口不深，布带却随着抬腿牵动；右腕仍缠药布，握拳只能用七分力。</p><p>叶承走在最前，玄衣已经换过，看不出昨日双戟留下多少疲惫。秦岚落后半级，袖间有一股水火丹药混合后的清苦气。三个人都没有为进主殿特意装作毫发无伤，伤单早由医棚送到殿中，衣服遮不住记录。</p><p>石阶两侧有洒扫童子。</p><p>他们等三人走过，便继续把落松针扫进竹筐。主殿再高，早课也不会因为今日择徒而停。陈玄走到第七十三阶时，另有一名杂役挑热水从侧道上来，桶沿蒸汽被山风吹散，谁也没有多看。</p><p>门前两名执事验候选令、名次牌与伤单。</p><p>看到陈玄号牌上那一整面小字，其中一人多翻了一次。</p><p>“主殿问话不得隐瞒伤势。若长老要求试招，医棚标注的禁式仍然有效。”</p><p>“是。”</p><p>殿门开启。</p><p>殿内没有想象中那么暗。白玉地面映着天窗光，柱间坐着各峰长老与执事。有人翻阅前三名册，有人在看叶承的火灵根谱，也有人把秦岚的丹试记录与家族供养单摆在一起。</p><p>择徒不只看一场胜负。</p><p>一个弟子修什么、要多少资源、峰内有没有合适传承、将来能承担什么差事，都是账。灵根并非羞辱人的两个字，也不是决定人格的判词，却真实影响修炼速度与每一次破境成本。</p><p>主位执事长老宣读前三。</p><p>“叶承，炼气九层，火灵根，短戟与长戟兼修。”</p><p>“秦岚，炼气九层，水火双灵根，丹道乙上。”</p><p>“陈玄，炼气六层，金木水火四属性灵根，药园出身，修《青元剑诀》第一重；大比第三，未收剑势一式，医棚禁练一月。”</p><p>最后一句读完，殿中有人抬头。</p><p>不是因为“第三”有多惊人。</p><p>是简册没有把那一式写成已经创成的“青莲剑歌”，而是照伤单写了未收与禁练。昨日场边流传的漂亮名字，到主殿里先被还原成一项尚有风险的技术事实。</p><p>叶承先被火云峰长老问了三件事：为何临场换短戟，长戟与短戟灵力路线能否共用，若峰内只给一种兵器资源，他选哪一件。</p><p>叶承选长戟。</p><p>“短戟是为陈玄临时换。我的根仍在长兵。”</p><p>火云峰长老没有因他决赛取胜便省掉问题，问完才给出亲传席位。叶承行礼接受。</p><p>秦岚则被丹峰问药性冲突。她在水火灵根之间选了以水控炉、以火成丹的路，也指出自己昨日第二炉丹温判断错了一成。丹峰给她内门入室席位，半年丹试后再定是否亲传。</p><p>轮到陈玄，殿中安静得更久。</p><p>阵峰长老先开口：“四属性灵根修剑，筑基前尚可借技巧弥补，筑基后每一层都要更多灵物调和。剑峰资源不算丰厚，你可想过若十年未筑基，怎么办？”</p><p>“想过。”</p><p>“答案呢？”</p><p>“先确认是资源不够、行气有错，还是根基没有填满。能补便补，不能便换路。十年之前，弟子不替十年之后说一定能成。”</p><p>“倒是不喊非剑不可。”</p><p>“若剑路证明走不通，喊也不会让经脉变宽。”</p><p>旁边一名符峰长老翻名册：“你在黑风山撤离血阵，带回证据；大比又多次用出界规则。有人说你过于惜命，不像剑修。”</p><p>陈玄问：“剑修一定要死在能退的时候？”</p><p>“你在反问本座？”</p><p>“弟子想知道标准。”</p><p>符峰长老看了他片刻，没有动怒：“若身后有人呢？”</p><p>“先看我留下能不能让人活。黑风山郑衡让我带证据走，我留下只会多一名伤员；若我站的位置真能挡住追兵，便另算。”</p><p>“另算是什么意思？”</p><p>“算我能挡多久，谁能在这段时间出去。不能只算死得像不像剑修。”</p><p>这一次，殿内更静。</p><p>陈玄没有讲自己一定舍身，也没有讲自己只求活。他把问题重新落回具体的人、路与时间。</p><p>阵峰愿给一个记名位置。</p><p>符峰也愿收作执符弟子，三年后复核。</p><p>两条路都是真的。阵法与符箓能放大谨慎，也适合多属性灵力。只是两峰不会为一个四灵根弟子立即开亲传资源，陈玄同样明白。</p><p>“你愿选哪一峰？”主位长老问。</p><p>陈玄尚未回答，最末席有人把一片竹屑吹下桌。</p><p>“先把剑给我。”</p><p>昨日削竹的灰袍人坐在那里。茶还是冷的，桌上竹片已削成一把粗细不匀的小剑。他没有说“他归我”，只伸出手。</p><p>陈玄认出剑峰牌，双手奉上青锋剑。</p><p>“弟子陈玄，见过李首座。”</p><p>李清风没有拔剑先看锋口。</p><p>他先看剑鞘。</p><p>鞘口一道新裂，是第八章周宁火符后湿鞘受损；如今这柄青锋的鞘虽是后来配的，边缘又被黑风山血索磨出细痕。剑柄缠布换过两次，右侧比左侧磨得深，说明陈玄大多只用右手。</p><p>长剑出鞘。</p><p>剑身中段有韩牧土墙留下的灰白擦痕，靠近护手处则有顾长林银剑连续点出的四个小凹。最深一道来自叶承短戟，阵纹修补尚新。赵无锋玄铁枪留下的白痕在更前端，说明当时剑并未正面挡枪锋，而是斜贴枪杆。</p><p>李清风看得很慢。</p><p>没有让陈玄在伤势未愈时再出一遍青莲。</p><p>“刘嵩那场为何抛剑？”</p><p>“右手压刀，左手只需接剑。”</p><p>“孙铁那场为何不扭断肘？”</p><p>“他已选择出界，继续下手违反规则，也无必要。”</p><p>“顾长林若退，第三剑之后怎么办？”</p><p>“没有第四剑。我会输。”</p><p>“昨日为何不用？”</p><p>“医棚禁止。叶承也不会站着接。”</p><p>李清风拇指在剑脊上一处极浅弯痕按了按：“还有呢？”</p><p>陈玄想了一会儿：“那一剑的线路是错的。赢过一次，仍是错。”</p><p>李清风这才把剑放到桌上。</p><p>阵峰长老道：“你问的都是擂台。灵根的账呢？”</p><p>“你们已经看过根。”李清风道，“我今日看剑。”</p><p>“剑能替他吸灵？”</p><p>“不能。”</p><p>“剑能替他筑基？”</p><p>“也不能。”</p><p>“那你十年不收徒，准备收一个四灵根？”</p><p>李清风没有用一句“我不看根”把真实成本抹掉。</p><p>“剑峰过去三十年择徒，先筛灵根，再看剑心。筛得很快，收来的弟子也大多练得快。”他看向桌上青锋，“可其中不少人把剑当入内门的牌、争资源的秤，基础三年不肯拆一式。陈玄的根慢，是真的；他肯把六十剑拆成三段、肯承认赢过的路仍然错，也是真的。”</p><p>他抬眼看陈玄。</p><p>“我想验证剑峰的次序是否放反了。不是替你证明四灵根胜过天灵根，也不是保证你一定筑基。你若入我门下，资源按峰规给，额外所需要以课业与贡献换；六个月一核，剑与境界有一项虚浮，我会停你的进阶。”</p><p>这不是当众赐下一条通天路。</p><p>是一个师父把自己要验证的东西、能给什么、不会给什么都说在前面。</p><p>“你可愿意？”</p><p>陈玄没有立刻跪。</p><p>他先问：“若弟子六个月后证明不适合剑峰？”</p><p>“我会告诉你哪里不适合。你可转阵峰、回药园，也可留下做普通剑峰弟子。亲传名分不是锁链。”</p><p>“若弟子走得慢？”</p><p>“慢不是错。拿伤势装进度，拿别人当耗材，才是。”</p><p>陈玄双膝落地。昨日膝伤碰到白玉，痛得小腿绷紧，腰背没有晃。</p><p>“弟子愿意。拜见师父。”</p><p>李清风没有立刻叫起。</p><p>“为何握剑？”</p><p>陈玄看着自己按在地上的手。</p><p>最早在青石村，他握木棍与柴刀，是怕父亲失踪后再没有人替自己挡。岁试握青铁剑，是为了从外门挤出一条路。黑风山里，郑衡点燃雷符，陆炳斩断腿线，又让“活下来”多了别的分量。</p><p>“最早只为自己活。”他说，“后来才知道，有时活下来是为了把话带回去，有时出剑是为了让别人也有路活。”</p><p>“若两者冲突？”</p><p>“先看我留下有没有用。若有，留下；若只是多死一个，便走，带能带的东西回来。”</p><p>李清风点头：“答案不漂亮，能用。起来。”</p><p>拜师礼没有异象。</p><p>执事递来剑峰内门令、两套青纹道袍与亲传课业册。内门令比外门腰牌轻，背面多一柄竹剑纹。课业册却很厚，第一页便列着晨课、月考、任务贡献与伤势停练规则。</p><p>资源堂长老当殿问了一句：“亲传份额按剑峰旧例，还是因四灵根另加调和丹？”</p><p>陈玄抬眼。</p><p>四灵根修炼耗费更多，这是事实。若宗门愿意多给，拒绝并不会显得更有骨气，只可能让路平白变窄。可多给的东西从哪里来、凭什么给，也该说清。</p><p>李清风道：“前三个月按旧例。每月灵石、灵米、养气丹与练剑台时辰照册。三个月后验他四气吸纳损耗，再决定是否以课业贡献增换调和丹。”</p><p>“不直接加？”</p><p>“尚未查明需要多少，先加只会让他把丹药当作四灵根必然缺口。”李清风翻到课业册末页，“若吸纳路线有错，先改路线；若确是灵根所限，再拿实数来换。额外资源不从其他弟子份额里平挪，由剑峰任务库出。”</p><p>资源堂长老把这几句写进分配页，又让陈玄按印。</p><p>李清风不是用“亲传”二字替他抹掉资源差距，也没有把差距变成可以随意多领的理由。先量，再给；多用的部分由师门承担，也由弟子以课业补回。</p><p>陈玄按下指印时，第一次感觉到师门的分量不只在有人替他说话。</p><p>还在有人愿意把将来可能发生的麻烦，提前写成双方都看得见的规矩。</p><p>陈玄先翻伤势停练。</p><p>李清风看见：“明日寅时上峰。今晚不许练剑。”</p><p>“是。”</p><p>“还有，那式未收剑势不叫青莲剑歌。”</p><p>“弟子没有取名。”</p><p>“很好。什么时候能收，什么时候再谈名字。”</p><p>叶承与秦岚各有归属。三人出殿时互相行礼，不说以后谁更高。叶承仍要回火云峰决定长短兵器如何共修，秦岚还有半年丹试，陈玄则有六个月第一次课业核查。名次只把门打开，门后各有各的难处。</p><p>王道全在殿外松树下等。</p><p>“亲传？”</p><p>“六个月一核。”</p><p>“那也是亲传。”他的扇子先快后慢，“外面已有人查你那朵青莲从哪来。我没放假消息，只把公开能查的三条真线都摆出去：藏经阁有《青元剑诀》，药园有你两年练剑记录，顾长林也说那式是临场未收。真话多了，他们便不容易只盯一处。”</p><p>“花了多少？”</p><p>“三顿茶，两次人情。记账。”</p><p>“我何时让你做了？”</p><p>“所以你可以不认。”王道全看着他，“但我已经做完。”</p><p>陈玄沉默片刻：“认一半。”</p><p>“七成。”</p><p>“六成。”</p><p>“成交。”</p><p>真正的道贺到这里才结束。</p><p>傍晚，陈玄回药园收拾东西。</p><p>几件旧衣、父亲留下的《山药札记》、青锋剑、二手储物袋，还有藏在贴身暗袋里的掌天瓶。正式外门腰牌没有丢，他把它与第一块试役木牌放在一起。人往高处走，不必把走过的低处扔掉。</p><p>鲁老头站在门口，手里仍是那柄旧药锄。</p><p>“剑峰风大。”老人说，“药田的土吹不上去，你那些灵根的毛病照样会跟着。”</p><p>“知道。”</p><p>“李清风教剑挑剔，煮面更难吃。别为了师父面子硬说好吃。”</p><p>陈玄抬头：“您认识师父？”</p><p>鲁老头用烟杆敲了一下门框：“青云宗就这么几座峰，认识有什么稀奇。”</p><p>说完便不肯再谈。</p><p>陈玄没有追问。</p><p>老人把旧药锄往墙角一靠：“这把不送你。丁字园还有新人要用。想翻土，自己回来借。”</p><p>“好。”</p><p>“三号寒髓草月底记温，别入了剑峰便忘。”</p><p>“每月回来两次。”</p><p>“一次便够。剑没学明白，来十次也只是抢我的活。”</p><p>鲁老头转身走出几步。</p><p>陈玄忽然叫住他：“鲁叔。”</p><p>老人没有回头，只停了一下。</p><p>“这两年，多谢。”</p><p>“谢什么？药园给你发过工钱。”</p><p>“工钱是药园的。”</p><p>半块饼、旧药锄、黑风山前那张不说吉利话的嘴，都不在工钱里。</p><p>鲁老头沉默一会儿，摆了摆烟杆：“去了剑峰，先看他让你做什么，别急着显本事。”</p><p>暮色里，佝偻背影沿药沟走远。</p><p>陈玄没有把旧药锄带走。</p><p>夜里，木屋空出一半。他把剑峰令与《山药札记》放在桌上，旁边是医棚写满限制的伤单。</p><p>主殿里，李清风说先看剑。</p><p>不是因为灵根从此不重要。</p><p>而是灵根的难处人人都看得见，剑上的选择却要有人愿意一处处看。</p><p>明日寅时，剑峰。</p><p>陈玄吹熄油灯，没有再出一剑。</p><p>（第十九章完）</p>',163)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
